    if (!fs.existsSync('package.json')) {
      throw new Error('package.json not found. Please ensure it exists in the project root.');
    }

    // Update package-lock.json using npm
    execSync('npm update --package-lock-only', { stdio: 'inherit' });

    console.log('package-lock.json updated successfully.');
